import struct, json
from collections import defaultdict, deque
import numpy as np

stl_path = "/root/scan_data.stl"
density_table_path = "/root/material_density_table.md"
output_path = "/root/mass_report.json"

def parse_density_table(path):
    densities = {}
    with open(path, "r") as f:
        for line in f:
            if "|" in line and line.strip().startswith("|") and line.count("|") >= 4:
                parts = [x.strip() for x in line.strip().split("|")]
                try:
                    mat_id = int(parts[1].replace("**", ""))
                    density = float(parts[3].split()[0])
                    densities[mat_id] = density
                except:
                    continue
    return densities

def parse_stl(path):
    with open(path, "rb") as f:
        header = f.read(80)
        n_tri, = struct.unpack("<I", f.read(4))
        triangles = []
        for _ in range(n_tri):
            data = f.read(50)
            if len(data) < 50:
                break
            normal = struct.unpack("<3f", data[0:12])
            v1 = struct.unpack("<3f", data[12:24])
            v2 = struct.unpack("<3f", data[24:36])
            v3 = struct.unpack("<3f", data[36:48])
            mat_id = struct.unpack("<H", data[48:50])[0]
            triangles.append({
                "vertices": [v1, v2, v3],
                "material_id": mat_id
            })
        return triangles

def vertex_hash(v):
    # Quantize to 1e-5 mm for robust matching
    return tuple([round(x, 5) for x in v])

def build_connectivity(triangles):
    vertex_to_tris = defaultdict(list)
    for idx, tri in enumerate(triangles):
        for v in tri["vertices"]:
            vertex_to_tris[vertex_hash(v)].append(idx)
    neighbors = defaultdict(set)
    for idx, tri in enumerate(triangles):
        neighbor_set = set()
        for v in tri["vertices"]:
            for nidx in vertex_to_tris[vertex_hash(v)]:
                if nidx != idx:
                    neighbor_set.add(nidx)
        neighbors[idx] = neighbor_set
    return neighbors

def find_largest_component(triangles, neighbors):
    visited = set()
    largest = []
    for i in range(len(triangles)):
        if i in visited:
            continue
        q = deque([i])
        comp = []
        while q:
            t = q.popleft()
            if t in visited:
                continue
            visited.add(t)
            comp.append(t)
            for n in neighbors[t]:
                if n not in visited:
                    q.append(n)
        if len(comp) > len(largest):
            largest = comp
    return largest

def triangle_volume(v1, v2, v3):
    # Signed volume of tetrahedron with base triangle and apex at origin
    v1 = np.array(v1)
    v2 = np.array(v2)
    v3 = np.array(v3)
    return np.dot(np.cross(v1, v2), v3) / 6.0

def main():
    densities = parse_density_table(density_table_path)
    triangles = parse_stl(stl_path)
    neighbors = build_connectivity(triangles)
    main_part = find_largest_component(triangles, neighbors)
    # Assume all triangles in main part have same material id
    mat_ids = [triangles[i]["material_id"] for i in main_part]
    mat_id = max(set(mat_ids), key=mat_ids.count)
    density = densities.get(mat_id)
    if density is None:
        raise Exception(f"Material ID {mat_id} not found in density table")
    # Compute volume in cm^3
    volume = 0.0
    for i in main_part:
        v1, v2, v3 = triangles[i]["vertices"]
        volume += triangle_volume(v1, v2, v3)
    volume = abs(volume) / 1000.0  # STL units are mm^3, convert to cm^3
    mass = volume * density
    with open(output_path, "w") as f:
        json.dump({
            "main_part_mass": round(mass, 2),
            "material_id": mat_id
        }, f, indent=1)

main()
